class SmallestInfiniteSet {
    TreeSet<Integer> available;
    int counter;

    SmallestInfiniteSet() {
        available = new TreeSet<>();
        counter = 1;
        for (int i = 1; i <= 1000; i++) {
            available.add(i);
        }
    }

    int popSmallest() {
        int smallest = counter;
        if (available.contains(counter)) {
            available.remove(counter);
        } else {
            counter++;
        }
        return smallest;
    }

    void addBack(int num) {
        available.add(num);
    }
}
